import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { FaTasks, FaRobot, FaCoins, FaPlus, FaHistory, FaWallet, FaSignOutAlt } from 'react-icons/fa';

const Dashboard = () => {
  const { user, logout, isAgent, isUser } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('overview');

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  // Mock data
  const userTasks = [
    { id: 1, description: 'Summarize article about AI', status: 'completed', date: '2024-01-15', cost: 0.5 },
    { id: 2, description: 'Generate Python code', status: 'completed', date: '2024-01-14', cost: 0.8 },
    { id: 3, description: 'Write blog post', status: 'pending', date: '2024-01-13', cost: 1.2 }
  ];

  const agentServices = [
    { id: 1, name: 'Text Summarizer', category: 'Text Analysis', earnings: 2.5, tasks: 5 },
    { id: 2, name: 'Code Generator', category: 'Programming', earnings: 4.2, tasks: 8 }
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50">
      {/* Header */}
      <header className="bg-white shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center py-4">
            <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
            <div className="flex items-center space-x-4">
              <span className="text-gray-600">Welcome, {user?.name}</span>
              <button
                onClick={handleLogout}
                className="flex items-center text-gray-600 hover:text-gray-900 px-3 py-2 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <FaSignOutAlt className="mr-2" />
                Logout
              </button>
            </div>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid lg:grid-cols-4 gap-8">
          {/* Sidebar */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-xl shadow-lg p-6">
              <nav className="space-y-2">
                <button
                  onClick={() => setActiveTab('overview')}
                  className={`w-full text-left px-4 py-3 rounded-lg transition-colors ${
                    activeTab === 'overview' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:bg-gray-100'
                  }`}
                >
                  Overview
                </button>
                {isUser && (
                  <>
                    <button
                      onClick={() => setActiveTab('tasks')}
                      className={`w-full text-left px-4 py-3 rounded-lg transition-colors ${
                        activeTab === 'tasks' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:bg-gray-100'
                      }`}
                    >
                      <FaTasks className="inline mr-2" />
                      My Tasks
                    </button>
                    <button
                      onClick={() => setActiveTab('payments')}
                      className={`w-full text-left px-4 py-3 rounded-lg transition-colors ${
                        activeTab === 'payments' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:bg-gray-100'
                      }`}
                    >
                      <FaWallet className="inline mr-2" />
                      Payments
                    </button>
                  </>
                )}
                {isAgent && (
                  <>
                    <button
                      onClick={() => setActiveTab('services')}
                      className={`w-full text-left px-4 py-3 rounded-lg transition-colors ${
                        activeTab === 'services' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:bg-gray-100'
                      }`}
                    >
                      <FaRobot className="inline mr-2" />
                      My Services
                    </button>
                    <button
                      onClick={() => setActiveTab('earnings')}
                      className={`w-full text-left px-4 py-3 rounded-lg transition-colors ${
                        activeTab === 'earnings' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:bg-gray-100'
                      }`}
                    >
                      <FaCoins className="inline mr-2" />
                      Earnings
                    </button>
                  </>
                )}
              </nav>
            </div>
          </div>

          {/* Main Content */}
          <div className="lg:col-span-3">
            {activeTab === 'overview' && (
              <div className="space-y-6">
                {/* Welcome Card */}
                <div className="bg-white rounded-xl shadow-lg p-6">
                  <h2 className="text-2xl font-bold text-gray-900 mb-2">
                    Welcome back, {user?.name}!
                  </h2>
                  <p className="text-gray-600">
                    {isUser ? 'Ready to submit a new task?' : 'Check your agent performance and earnings.'}
                  </p>
                  {isUser && (
                    <button
                      onClick={() => navigate('/marketplace')}
                      className="mt-4 bg-gradient-to-r from-blue-600 to-purple-600 text-white px-6 py-3 rounded-lg hover:from-blue-700 hover:to-purple-700 transition-all inline-flex items-center"
                    >
                      <FaPlus className="mr-2" />
                      New Task
                    </button>
                  )}
                  {isAgent && (
                    <button
                      onClick={() => navigate('/register-agent')}
                      className="mt-4 bg-gradient-to-r from-purple-600 to-blue-600 text-white px-6 py-3 rounded-lg hover:from-purple-700 hover:to-blue-700 transition-all inline-flex items-center"
                    >
                      <FaPlus className="mr-2" />
                      Add Service
                    </button>
                  )}
                </div>

                {/* Stats Cards */}
                <div className="grid md:grid-cols-3 gap-6">
                  {isUser && (
                    <>
                      <div className="bg-white rounded-xl shadow-lg p-6">
                        <div className="flex items-center">
                          <FaTasks className="text-blue-600 text-2xl mr-4" />
                          <div>
                            <p className="text-2xl font-bold text-gray-900">{userTasks.length}</p>
                            <p className="text-gray-600">Total Tasks</p>
                          </div>
                        </div>
                      </div>
                      <div className="bg-white rounded-xl shadow-lg p-6">
                        <div className="flex items-center">
                          <FaCoins className="text-yellow-600 text-2xl mr-4" />
                          <div>
                            <p className="text-2xl font-bold text-gray-900">
                              {userTasks.reduce((sum, task) => sum + task.cost, 0).toFixed(1)}
                            </p>
                            <p className="text-gray-600">ALGO Spent</p>
                          </div>
                        </div>
                      </div>
                      <div className="bg-white rounded-xl shadow-lg p-6">
                        <div className="flex items-center">
                          <FaHistory className="text-green-600 text-2xl mr-4" />
                          <div>
                            <p className="text-2xl font-bold text-gray-900">
                              {userTasks.filter(t => t.status === 'completed').length}
                            </p>
                            <p className="text-gray-600">Completed</p>
                          </div>
                        </div>
                      </div>
                    </>
                  )}

                  {isAgent && (
                    <>
                      <div className="bg-white rounded-xl shadow-lg p-6">
                        <div className="flex items-center">
                          <FaRobot className="text-purple-600 text-2xl mr-4" />
                          <div>
                            <p className="text-2xl font-bold text-gray-900">{agentServices.length}</p>
                            <p className="text-gray-600">Services</p>
                          </div>
                        </div>
                      </div>
                      <div className="bg-white rounded-xl shadow-lg p-6">
                        <div className="flex items-center">
                          <FaCoins className="text-yellow-600 text-2xl mr-4" />
                          <div>
                            <p className="text-2xl font-bold text-gray-900">
                              {agentServices.reduce((sum, service) => sum + service.earnings, 0).toFixed(1)}
                            </p>
                            <p className="text-gray-600">ALGO Earned</p>
                          </div>
                        </div>
                      </div>
                      <div className="bg-white rounded-xl shadow-lg p-6">
                        <div className="flex items-center">
                          <FaTasks className="text-blue-600 text-2xl mr-4" />
                          <div>
                            <p className="text-2xl font-bold text-gray-900">
                              {agentServices.reduce((sum, service) => sum + service.tasks, 0)}
                            </p>
                            <p className="text-gray-600">Tasks Completed</p>
                          </div>
                        </div>
                      </div>
                    </>
                  )}
                </div>
              </div>
            )}

            {activeTab === 'tasks' && isUser && (
              <div className="bg-white rounded-xl shadow-lg p-6">
                <h3 className="text-xl font-bold text-gray-900 mb-4">My Tasks</h3>
                <div className="space-y-4">
                  {userTasks.map(task => (
                    <div key={task.id} className="border rounded-lg p-4">
                      <div className="flex justify-between items-start">
                        <div>
                          <p className="font-medium text-gray-900">{task.description}</p>
                          <p className="text-sm text-gray-500">{task.date}</p>
                        </div>
                        <div className="text-right">
                          <span className={`px-2 py-1 rounded text-sm ${
                            task.status === 'completed' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
                          }`}>
                            {task.status}
                          </span>
                          <p className="text-sm text-gray-600 mt-1">{task.cost} ALGO</p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'services' && isAgent && (
              <div className="bg-white rounded-xl shadow-lg p-6">
                <h3 className="text-xl font-bold text-gray-900 mb-4">My Services</h3>
                <div className="space-y-4">
                  {agentServices.map(service => (
                    <div key={service.id} className="border rounded-lg p-4">
                      <div className="flex justify-between items-center">
                        <div>
                          <h4 className="font-medium text-gray-900">{service.name}</h4>
                          <p className="text-sm text-gray-600">{service.category}</p>
                        </div>
                        <div className="text-right">
                          <p className="font-medium text-gray-900">{service.earnings} ALGO</p>
                          <p className="text-sm text-gray-600">{service.tasks} tasks</p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
